svg.script:
//!export-start
let _pb_run = false;        // Start / Stop
let _pb_reverse = false;    // Direction
let _pn_speed = 3;          // Rotation speed
let _pc_color = "#888";     // Blade color
//!export-end

const propeller = document.getElementById("propeller");
const blades = document.getElementById("blades");

let angle = 0;
let animationId = null;

function putValue(id, value){

  if(id === "_pb_run")
    _pb_run = (value === true || value === 1 || value === '1');

  if(id === "_pb_reverse")
    _pb_reverse = (value === true || value === 1 || value === '1');

  if(id === "_pn_speed")
    _pn_speed = Number(value);

  if(id === "_pc_color")
    _pc_color = value;

  updateColor();
  controlAnimation();
}

function updateColor(){

  blades.querySelectorAll("path").forEach(b =>
    b.setAttribute("fill", _pc_color)
  );
}

function animatePropeller(){

  if(_pb_reverse){
    angle -= _pn_speed;   // reverse
  } else {
    angle += _pn_speed;   // normal
  }

  propeller.setAttribute(
    "transform",
    "translate(100,100) rotate(" + angle + ")"
  );

  animationId = requestAnimationFrame(animatePropeller);
}

function controlAnimation(){

  if(_pb_run){
    if(!animationId)
      animatePropeller();
  } else {
    cancelAnimationFrame(animationId);
    animationId = null;
  }

}

updateColor();
controlAnimation();
